data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. For boundary checks, use:

| Need | MSTest Approach |
|---|---|
| Comparison | `Assert.IsTrue(actual > expected, "message")` |
| Range | `Assert.IsTrue(val >= lo && val <= hi, "message")` |
| Equality | `Assert.AreEqual(expected, actual, delta)` (for `double`) |
| Exceptions | `Assert.ThrowsException<T>(action)` |

The `double` overload of `AreEqual` takes a **delta** (tolerance) parameter, which is important for floating-point comparisons.

Here's a complete test class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333333)]
    public void CalculatePercentage_ReturnsExpected(int correct, int total, double expected)
    {
        double result = _calc.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result, 0.001, $"Expected ~{expected} but got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(3, 7);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Percentage {result} should be between 0 and 100");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade ─────────────────────────────────────────

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(95.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ───────────────────────────────────

    [TestMethod]
    public void NormalizeScore_BasicNormalization()
    {
        double result = _calc.NormalizeScore(40, 50);
        Assert.AreEqual(80.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.IsTrue(result <= 100.0,
            $"Normalized score {result} should not exceed 100");
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 50));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(10, 0));
    }
}
```

**Key patterns used:**

- **`Assert.AreEqual(expected, actual, delta)`** — the `double` overload with a tolerance (`0.001`) for floating-point comparison
- **`Assert.IsTrue(condition, message)`** — workaround for the missing comparison/range assertions; always include a message so failures are readable
- **`Assert.ThrowsException<T>`** — validates guard clauses
- **`[DataRow]` on boundary values** — tests grade thresholds at exact boundaries (e.g., `90.0` → A, `89.9` → B)
